patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..1c2b1d65feb2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4803,13 +4803,46 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     return nullptr;

   if (Instruction *NewICmp = foldICmpXNegX(I, Builder))
-    return NewICmp;
-
   const CmpInst::Predicate Pred = I.getPredicate();
   Value *X;
-
-  // Convert add-with-unsigned-overflow comparisons into a 'not' with compare.
-  // (Op1 + X) u</u>= Op1 --> ~Op1 u</u>= X
+  
+  Value *Y;
+  // icmp slt (sdiv X, Y), X -> icmp sgt X, 0
+  // icmp sle (sdiv X, Y), X -> icmp sge X, 0
+  // icmp sgt (sdiv X, Y), X -> icmp slt X, 0
+  // icmp sge (sdiv X, Y), X -> icmp sle X, 0
+  if (match(Op0, m_SDiv(m_Specific(Op1), m_Value(Y))) &&
+      (Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SLE ||
+       Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SGE)) {
+    ConstantRange CR = computeConstantRange(Y, /*ForSigned=*/true,
+                                            Q.IIQ.UseInstrInfo);
+    if (!CR.contains(APInt(CR.getBitWidth(), 0)) &&
+        !CR.contains(APInt(CR.getBitWidth(), 1)) &&
+        !CR.contains(APInt::getAllOnes(CR.getBitWidth()))) {
+      CmpInst::Predicate NewPred;
+      if (Pred == ICmpInst::ICMP_SLT) NewPred = ICmpInst::ICMP_SGT;
+      else if (Pred == ICmpInst::ICMP_SLE) NewPred = ICmpInst::ICMP_SGE;
+      else if (Pred == ICmpInst::ICMP_SGT) NewPred = ICmpInst::ICMP_SLT;
+      else NewPred = ICmpInst::ICMP_SLE;
+      return new ICmpInst(NewPred, Op1, ConstantInt::getNullValue(Op1->getType()));
+    }
+  }
+
+  // icmp sgt X, (sdiv X, Y) -> icmp sgt X, 0
+  // icmp sge X, (sdiv X, Y) -> icmp sge X, 0
+  // icmp slt X, (sdiv X, Y) -> icmp slt X, 0
+  // icmp sle X, (sdiv X, Y) -> icmp sle X, 0
+  if (match(Op1, m_SDiv(m_Specific(Op0), m_Value(Y))) &&
+      (Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SLE ||
+       Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SGE)) {
+    ConstantRange CR = computeConstantRange(Y, /*ForSigned=*/true,
+                                            Q.IIQ.UseInstrInfo);
+    if (!CR.contains(APInt(CR.getBitWidth(), 0)) &&
+        !CR.contains(APInt(CR.getBitWidth(), 1)) &&
+        !CR.contains(APInt::getAllOnes(CR.getBitWidth()))) {
+      return new ICmpInst(Pred, Op0, ConstantInt::getNullValue(Op0->getType()));
+    }
+  }
   if (match(Op0, m_OneUse(m_c_Add(m_Specific(Op1), m_Value(X)))) &&
       (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_UGE))
     return new ICmpInst(Pred, Builder.CreateNot(Op1), X);

